mapper.select:
/* 사용자 위젯 목록 dataDashboard.selectDashboardWidgetList */ SELECT W.WIDGET_ID , W.LOG_ID , W.TITLE , W.VIZ_TYPE , W.VIZ_CONFIG , W.COL_SPAN , W.SORT_ORD , A.Q_CONTENT AS SQL_TITLE , A.TTSQ AS SQL_CONTENT , A.TTSQ_PARAM , A.AGENT_ID , B.AGENT_NM , A.REF_ID AS DATAMART_ID , C.DM_NM AS DATAMART_NM FROM TB_USER_DASHBOARD_WIDGET W JOIN TB_CHAT_LOG A ON W.LOG_ID = A.LOG_ID LEFT JOIN TB_AGT B ON A.AGENT_ID = B.AGENT_ID LEFT JOIN TB_DM C ON A.REF_ID = C.DATAMART_ID WHERE W.USER_ID = #{userId}
AND W.WIDGET_ID = #{widgetId}
ORDER BY W.SORT_ORD, W.WIDGET_ID

mapper.insert:
/* 위젯 저장 dataDashboard.saveDashboardWidget */
INSERT INTO TB_USER_DASHBOARD_WIDGET (
      WIDGET_ID
    , USER_ID
    , LOG_ID
    , TITLE
    , VIZ_TYPE
    , VIZ_CONFIG
    , TTSQ_PARAM
    , COL_SPAN
    , SORT_ORD
    , CREATE_DT
) VALUES (
      #{widgetId}
    , #{userId}
    , #{logId}
    , #{title}
    , #{vizType}
    , #{vizConfig}
    , #{ttsqParam}
    , #{colSpan, jdbcType=INTEGER}
    , #{sortOrd, jdbcType=INTEGER}
    , NOW()
)
ON DUPLICATE KEY UPDATE
      TITLE      = #{title}
    , VIZ_TYPE   = #{vizType}
    , VIZ_CONFIG = #{vizConfig}
    , COL_SPAN   = #{colSpan, jdbcType=INTEGER}
    , SORT_ORD   = #{sortOrd, jdbcType=INTEGER}
    , MODIFY_DT  = NOW()

mapper.delete:
/* 위젯 삭제 dataDashboard.deleteDashboardWidget */
DELETE FROM TB_USER_DASHBOARD_WIDGET
WHERE WIDGET_ID = #{widgetId}
  AND USER_ID   = #{userId}

mapper.update:
/* 위젯 순서 변경 dataDashboard.updateDashboardWidgetOrder */
UPDATE TB_USER_DASHBOARD_WIDGET
SET SORT_ORD = CASE WIDGET_ID

        WHEN #{item.widgetId} THEN #{item.sortOrd}

END
, MODIFY_DT = NOW()
WHERE USER_ID = #{userId}
  AND WIDGET_ID IN

    #{item.widgetId}
